// Backfill-Konfiguration.
// onlyVorgangKey: leer = alle bereits archivierten Vorgänge, sonst nur diesen einen
// (zum Testen vor dem großen Lauf).

return [{
  json: {
    onlyVorgangKey: ""
  }
}];

const j = $input.item.json;
let id = null;
if (Array.isArray(j.results)) {
  id = j.results[0]?.id ?? null;
} else if (j.id !== undefined) {
  id = j.id;
}
if (!id) {
  console.warn('[Backfill/Paperless] Tag "ALLRIS": konnte keine ID ermitteln.');
}
return { json: { id, name: 'ALLRIS' } };

const j = $input.item.json;
let id = null;
if (Array.isArray(j.results)) {
