return { json: { id, name: 'Dokument' } };

// Bereinigt einen Ordnerpfad-Wert aus der DataTable.
function sanitizeFolder(raw) {
  const s = (raw || '').trim();
  if (s.toLowerCase() === 'null' || s.toLowerCase() === 'undefined' || s === '-') return '';
  return s;
}

const cfg = $('Backfill Konfiguration').first()?.json || {};
const onlyVorgangKey = (cfg.onlyVorgangKey || '').trim();

const out = [];
let alreadyBackfilled = 0;
for (const item of items) {
  const j = item.json;
  const folder = sanitizeFolder(j.nextcloudFolder);
  if (!folder) continue;
  if (onlyVorgangKey) {
    if (j.vorgangKey !== onlyVorgangKey) continue;
  } else if (j.paperlessBackfilledAt) {
    // Vorgang wurde in einem frueheren Stundenlauf bereits vollstaendig zu Paperless
    // synchronisiert (siehe 'Paperless Backfill markieren') - nicht bei jedem Lauf
    // die komplette Historie neu scannen, das hat zuvor zu andauerndem Dubletten-
    // Zuwachs gefuehrt.
    alreadyBackfilled++;
    continue;
  }
  out.push({ json: { ...j, nextcloudFolder: folder } });
}

out.sort((a, b) => {
  const aDate = Date.parse(a.json.firstseen || a.json.createdAt || '') || 0;
  const bDate = Date.parse(b.json.firstseen || b.json.createdAt || '') || 0;
  return aDate - bDate;
});

console.log(`[Backfill] ${out.length} bereits archivierte Vorgänge zum Nachziehen (aus ${items.length} DataTable-Zeilen, ${alreadyBackfilled} bereits vollständig synchronisiert).`);
return out;

// Verwandelt das Nextcloud-Listing des '01_originale'-Ordners in ein Item pro Datei.
// Gibt IMMER mindestens ein Item zurück (auch bei leerem Ordner/Fehler), damit die
// SplitInBatches-Schleife nie hängen bleibt.
//
// Der Nextcloud-'list'-Node liefert pro Eintrag ein 'path' (WebDAV-href, i.d.R.
// URL-kodiert und MIT Server-/User-Präfix wie /remote.php/dav/files/<user>/...).
// Für den nachfolgenden 'download'-Node wird aber der reine, dekodierte Pfad ab
// dem bekannten Vorgangsordner benötigt (gleiches Format wie im Haupt-Workflow,
// z.B. /DiePARTEI/Allris/2026/xxx/01_originale/datei.pdf) - NICHT selbst neu
// zusammensetzen, sondern aus der Href ableiten, um Kodierungs-/Präfix-Mismatches
// zu vermeiden (führte zuvor zu 0-KB-Downloads, weil 'download' Statuscodes nicht prüft).

const vorgang = $('Loop Vorgänge').first().json;
const rawItems = $input.all();

const errored = rawItems.length === 1 && rawItems[0].json && rawItems[0].json.error;
if (errored) {
  console.warn(`[Backfill] ${vorgang.vorgangKey}: Nextcloud-Liste fehlgeschlagen: ${JSON.stringify(rawItems[0].json.error)}`);
}

function isFileEntry(f) {
  const type = String(f.type || '').toLowerCase();
  if (type) return type === 'file';
  const p = f.path || f.href || f.filename || f.name || '';
  return !!p && !String(p).endsWith('/');
}

const files = errored ? [] : rawItems.map(i => i.json).filter(isFileEntry);

if (files.length === 0) {
  if (!errored) {
    console.warn(`[Backfill] ${vorgang.vorgangKey}: keine Dateien in "${vorgang.nextcloudFolder}/01_originale" gefunden.`);
  }
  return [{
    json: {
      vorgangKey: vorgang.vorgangKey,
      nextcloudFolder: vorgang.nextcloudFolder,
      _noFiles: true
    }
  }];
}

return files.map(f => {
  const rawHref = f.path || f.href || f.filename || '';
  let decodedHref = String(rawHref);
  try {
    decodedHref = decodeURIComponent(decodedHref);
  } catch (e) {
    console.warn(`[Backfill] Konnte Href nicht dekodieren ("${rawHref}"): ${e.message}`);
  }

  const fileName = f.name || decodedHref.split('/').filter(Boolean).pop() || 'unbekannt';

  // Ab dem bekannten Vorgangsordner schneiden - robust gegen unbekanntes
  // WebDAV-Präfix (remote.php/dav/files/<user>/... vs. remote.php/webdav/...).
  const anchor = vorgang.nextcloudFolder;
  const anchorIdx = decodedHref.indexOf(anchor);
  const fullPath = anchorIdx !== -1
    ? decodedHref.substring(anchorIdx)
    : `${vorgang.nextcloudFolder}/01_originale/${fileName}`;

  if (anchorIdx === -1) {
    console.warn(`[Backfill] Konnte "${anchor}" nicht in Href "${decodedHref}" finden, nutze zusammengesetzten Pfad als Fallback.`);
  }

  return {
    json: {
      vorgangKey: vorgang.vorgangKey,
      nextcloudFolder: vorgang.nextcloudFolder,
      fileName,
      fullPath,
      _noFiles: false
    }
  };
});

const item = $input.item;
const j = item.json || {};
const binary = item.binary || {};
const hasBinary = !!binary.data;

let fileSize = 0;
if (hasBinary) {
  try {
    const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
    fileSize = buf.length;
  } catch (e) {
    console.warn(`[Backfill] Konnte Binärdaten nicht prüfen (${j.vorgangKey || '?'} / ${j.fileName || '?'}): ${e.message}`);
  }
}

const downloadOk = hasBinary && fileSize > 0 && !j.error;

if (!downloadOk) {
  console.warn(`[Backfill] Download fehlgeschlagen: ${j.vorgangKey || '?'} / ${j.fileName || '?'} (hasBinary=${hasBinary}, size=${fileSize})`);
}

return {
  json: { ...j, _downloadOk: downloadOk, _downloadFileSize: fileSize },
  binary
};

// Baut den Paperless-Dubletten-Titel und löst Tag/Correspondent/DocumentType-IDs auf.
// Analog zu 'Paperless Titel bauen' im Haupt-Nextcloud-Workflow, aber mit Dateiname
// aus dem Nextcloud-Listing statt aus documentsJson.

const j = $input.item.json;

function sanitize(str, maxLen) {
  return String(str || '')
    .replace(/[\/\\:*?"<>|\r\n]/g, '_')
    .replace(/\s+/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '')
    .substring(0, maxLen || 150);
}

const paperlessTitle = sanitize(`${j.vorgangKey || 'unbekannt'}_${j.fileName || ''}`, 150);

function inferDocType(fileName) {
  const f = String(fileName || '').toLowerCase();
  if (f.includes('_original')) return 'original';
  if (f.includes('_anlage')) return 'anlage';
  return 'document';
}

const tagId = $('Paperless Normalize Tag ALLRIS').first()?.json?.id || null;
const correspondentId = $('Paperless Normalize Correspondent Stadt Goslar').first()?.json?.id || null;

const docType = inferDocType(j.fileName);
let documentTypeId = null;
if (docType === 'original') {
  documentTypeId = $('Paperless Normalize DocType Original').first()?.json?.id || null;
} else if (docType === 'anlage') {
  documentTypeId = $('Paperless Normalize DocType Anlage').first()?.json?.id || null;
} else {
  documentTypeId = $('Paperless Normalize DocType Dokument').first()?.json?.id || null;
}

const paperlessMetaOk = !!(tagId && correspondentId && documentTypeId);
if (!paperlessMetaOk) {
  console.warn(`[Backfill] Metadaten (Tag/Correspondent/DocType) unvollständig für ${paperlessTitle} - Upload läuft nur mit Titel.`);
}

return {
  json: {
    ...j,
    paperlessTitle,
    paperlessTagId: tagId,
    paperlessCorrespondentId: correspondentId,
    paperlessDocumentTypeId: documentTypeId,
    paperlessMetaOk
  },
  binary: $input.item.binary || {}
};

// Der HTTP-GET-Node 'Paperless Prüfe Dokument (Backfill)' liefert nur JSON
// (count/results) zurück und verwirft dabei die Binärdaten der Datei.
// Hier werden sie aus 'Paperless Titel bauen (Backfill)' wiederhergestellt,
// bevor der Upload-Node sie braucht.

const j = $input.item.json;
const original = $('Paperless Titel bauen (Backfill)').item;

return {
  json: j,
  binary: original.binary || {}
};

// Zweig wird auch angesteuert, wenn die Dubletten-Pruefung selbst fehlgeschlagen ist
// (siehe 'IF Paperless existiert bereits? (Backfill)') - in dem Fall NICHT hochladen,
// da sonst bei jedem transienten API-Fehler ein Duplikat entstehen wuerde. Stattdessen
// hier als Skip protokollieren und im naechsten Lauf erneut versuchen.
const j = $input.item.json;
return { json: { ...j, _paperlessSkippedExisting: !j.error, _paperlessSkippedCheckFailed: !!j.error } };

const response = $input.item.json || {};

// HTTP- und Skip-Nodes koennen ihren Eingangskontext durch eine reine
// Antwortstruktur ersetzen. Den vorgangKey deshalb vor der Aggregation aus dem
// letzten gemeinsamen, item-verknuepften Node wiederherstellen.
let context = {};
try {
  context = $('Paperless Titel bauen (Backfill)').item.json || {};
} catch (e) {
  context = {};
}

const j = { ...context, ...response };

if (j._paperlessSkippedCheckFailed) {
  console.warn(`[Backfill/Paperless] Übersprungen (Dublettenprüfung fehlgeschlagen, Retry im nächsten Lauf): ${j.paperlessTitle}`);
} else if (j._paperlessSkippedExisting) {
  console.log(`[Backfill/Paperless] Übersprungen (existiert bereits): ${j.paperlessTitle}`);
} else if (j.error) {
  console.warn(`[Backfill/Paperless] Fehler bei "${j.paperlessTitle}": ${j.error.message || j.error}`);
} else {
  console.log(`[Backfill/Paperless] Hochgeladen: ${j.paperlessTitle}`);
}

return {
  json: {
    vorgangKey: j.vorgangKey || '',
    paperlessTitle: j.paperlessTitle || '',
    _paperlessSkippedExisting: j._paperlessSkippedExisting === true,
    _paperlessSkippedCheckFailed: j._paperlessSkippedCheckFailed === true,
    error: j.error || null
  }
};

// Fasst alle Datei-Ergebnisse EINES Vorgangs (kann 0, 1 oder mehrere Items sein,
// je nach Anzahl Dateien in '01_originale') zu einem einzigen Abschlussurteil
// zusammen. Nur wenn wirklich ALLES fehlerfrei war (kein Downloadfehler, keine
// fehlgeschlagene Dublettenpruefung, kein Upload-Fehler), gilt der Vorgang als
// vollstaendig zu Paperless synchronisiert und wird per 'paperlessBackfilledAt'
// markiert - sonst wird er im naechsten Stundenlauf erneut geprueft.

const results = $input.all();
const resultRows = results.map(i => i.json || {});
const vorgangKeys = [...new Set(resultRows.map(j => String(j.vorgangKey || '').trim()).filter(Boolean))];

if (vorgangKeys.length !== 1) {
  throw new Error(`[Backfill] Erwartet genau einen vorgangKey in den Ergebnissen, erhalten: ${vorgangKeys.length}.`);
}

const vorgangKey = vorgangKeys[0];
const failed = resultRows.some(j =>
  j._skippedReason === 'download_failed' ||
  j._paperlessSkippedCheckFailed === true ||
  !!j.error
);

console.log(`[Backfill] ${vorgangKey}: ${failed ? 'nicht vollständig - wird beim nächsten Lauf erneut geprüft' : 'vollständig synchronisiert'}.`);

return [{ json: { vorgangKey, _backfillComplete: !failed } }];

const retryCount = Number($json.retry_count || 0) + 1;
const delayMinutes = Math.min(1440, 15 * Math.pow(2, Math.max(0, retryCount - 1)));
return { json: { ...$json, retry_count: retryCount, next_retry_at: $now.plus({ minutes: delayMinutes }).toISO(), paperless_error_message: 'Mindestens ein Dokument konnte nicht vollständig nach Paperless synchronisiert werden.' } };
